da.';} else {$pdo->prepare('INSERT INTO erp_machines(code,name,brand,model,serial_number,manufacturing_year,department_id,location,owner_user_id,status,criticality,nominal_capacity,capacity_unit,cycle_time,cycle_time_unit,operators_required,supplier,service_provider,purchase_date,next_maintenance_date,manual_url,characteristics,risks,limitations,notes,created_by,updated_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute([...array_slice($data,0,25),$userId,$userId]); gt_org_audit($pdo,$userId,'erp.machines.create','erp_machines',(int)$pdo->lastInsertId(),[],$_POST); $flashSuccess='Máquina criada.'; }} elseif($action==='delete'){ $id=(int)$_POST['id']; $pdo->prepare('UPDATE erp_machines SET deleted_at=CURRENT_TIMESTAMP,is_active=0,updated_by=? WHERE id=?')->execute([$userId,$id]); gt_org_audit($pdo,$userId,'erp.machines.delete','erp_machines',$id,[],[]); $flashSuccess='Máquina removida.'; }}catch(Throwable $e){$flashError='Erro: '.$e->getMessage();}}
$q=trim($_GET['q']??'');$status=trim($_GET['status']??'');$dep=(int)($_GET['department_id']??0);$where=['m.deleted_at IS NULL'];$args=[];if($q!==''){$where[]='(m.code LIKE ? OR m.name LIKE ? OR m.brand LIKE ? OR m.model LIKE ? OR m.supplier LIKE ?)';for($i=0;$i<5;$i++)$args[]="%$q%";}if($status!==''){$where[]='m.status=?';$args[]=$status;}if($dep){$where[]='m.department_id=?';$args[]=$dep;} $st=$pdo->prepare('SELECT m.*,d.name department_name,u.name owner_name,(SELECT COUNT(*) FROM hr_machine_competencies c JOIN users uu ON uu.id=c.user_id WHERE c.machine_id=m.id AND c.level>=3 AND COALESCE(uu.is_active,1)=1 AND c.deleted_at IS NULL) autonomous FROM erp_machines m LEFT JOIN hr_departments d ON d.id=m.department_id LEFT JOIN users u ON u.id=m.owner_user_id WHERE '.implode(' AND ',$where).' ORDER BY m.is_active DESC,m.code');$st->execute($args);$machines=$st->fetchAll(PDO::FETCH_ASSOC);$deps=$pdo->query('SELECT * FROM hr_departments ORDER BY name')->fetchAll(PDO::FETCH_ASSOC);$people=$pdo->query('SELECT id,name FROM users WHERE COALESCE(is_active,1)=1 ORDER BY name')->fetchAll(PDO::FETCH_ASSOC);
