<div class="container-fluid py-4"><?php if($flashSuccess):?><div class="alert alert-success"><?=h($flashSuccess)?></div><?php endif;?><?php if($flashError):?><div class="alert alert-danger"><?=h($flashError)?></div><?php endif;?><form class="card card-body mb-3"><div class="row g-2"><div class="col"><input class="form-control" name="q" value="<?=h($q)?>" placeholder="Pesquisar máquina, marca, modelo, setor ou fornecedor"></div><div class="col-md-2"><select class="form-select" name="status"><option value="">Todos os estados</option><?php foreach(['operational'=>'Operacional','maintenance'=>'Em manutenção','broken'=>'Avariada','stopped'=>'Parada','inactive'=>'Desativada'] as $k=>$v):?><option value="<?=$k?>" <?=$status===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></div><div class="col-md-2"><select class="form-select" name="department_id"><option value="">Departamentos</option><?php foreach($deps as $d):?><option value="<?=$d['id']?>" <?=$dep===(int)$d['id']?'selected':''?>><?=h($d['name'])?></option><?php endforeach;?></select></div><div class="col-auto"><button class="btn btn-primary">Filtrar</button></div></div></form><div class="row g-3 mb-3"><?php $cards=['Máquinas'=>count($machines),'Operacionais'=>count(array_filter($machines,fn($m)=>$m['status']==='operational')),'Críticas'=>count(array_filter($machines,fn($m)=>in_array($m['criticality'],['high','critical'],true))),'Sem responsável'=>count(array_filter($machines,fn($m)=>empty($m['owner_user_id']))),'Manutenção vencida'=>count(array_filter($machines,fn($m)=>!empty($m['next_maintenance_date'])&&$m['next_maintenance_date']<date('Y-m-d'))),'Sem operadores'=>count(array_filter($machines,fn($m)=>(int)$m['autonomous']===0))]; foreach($cards as $l=>$v):?><div class="col-md-2"><div class="card card-body"><small class="text-muted"><?=h($l)?></small><strong class="fs-3"><?=$v?></strong></div></div><?php endforeach;?></div><div class="card mb-3"><div class="card-body"><h2 class="h5">Nova / editar máquina</h2><form method="post" class="row g-2"><?=csrf_input()?><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=h($_GET['edit']??'')?>"><div class="col-md-2"><input required class="form-control" name="code" placeholder="Código interno"></div><div class="col-md-4"><input required class="form-control" name="name" placeholder="Designação"></div><div class="col-md-2"><input class="form-control" name="brand" placeholder="Marca"></div><div class="col-md-2"><input class="form-control" name="model" placeholder="Modelo"></div><div class="col-md-2"><input class="form-control" name="serial_number" placeholder="N.º série"></div><div class="col-md-2"><input class="form-control" type="number" name="manufacturing_year" placeholder="Ano"></div><div class="col-md-3"><select class="form-select" name="department_id"><option value="">Departamento</option><?php foreach($deps as $d):?><option value="<?=$d['id']?>"><?=h($d['name'])?></option><?php endforeach;?></select></div><div class="col-md-3"><select class="form-select" name="owner_user_id"><option value="">Responsável técnico</option><?php foreach($people as $p):?><option value="<?=$p['id']?>"><?=h($p['name'])?></option><?php endforeach;?></select></div><div class="col-md-2"><select class="form-select" name="status"><option value="operational">Operacional</option><option value="maintenance">Em manutenção</option><option value="broken">Avariada</option><option value="stopped">Parada</option><option value="inactive">Desativada</option></select></div><div class="col-md-2"><select class="form-select" name="criticality"><option value="medium">Média</option><option value="low">Baixa</option><option value="high">Alta</option><option value="critical">Crítica</option></select></div><div class="col-md-2"><input class="form-control" type="number" name="operators_required" min="0" value="0" placeholder="Operadores"></div><div class="col-md-3"><input class="form-control" name="location" placeholder="Localização"></div><div class="col-md-3"><input class="form-control" name="supplier" placeholder="Fornecedor"></div><div class="col-md-3"><input class="form-control" name="service_provider" placeholder="Assistência"></div><div class="col-md-3"><input class="form-control" type="date" name="next_maintenance_date"></div><div class="col-12"><textarea class="form-control" name="notes" placeholder="Características, riscos, limitações e observações"></textarea></div><div class="col-12"><button class="btn btn-primary">Guardar</button></div></form></div></div><div class="row g-3"><?php foreach($machines as $m):?><div class="col-md-6"><div class="card h-100"><div class="card-body"><span class="badge text-bg-secondary"><?=h($m['status'])?></span><h3 class="h5"><?=h($m['code'].' · '.$m['name'])?></h3><p class="text-muted"><?=h(trim(($m['brand']??'').' '.($m['model']??''))?:'Marca e modelo por definir')?></p><div class="row g-2"><div class="col"><div class="bg-light p-2 rounded"><small>Localização</small><br><strong><?=h($m['department_name']?:$m['location']?:'Por definir')?></strong></div></div><div class="col"><div class="bg-light p-2 rounded"><small>Responsável</small><br><strong><?=h($m['owner_name']?:'Por definir')?></strong></div></div><div class="col"><div class="bg-light p-2 rounded"><small>Autónomos</small><br><strong><?=h((string)$m['autonomous'])?></strong></div></div></div><p class="mt-2"><?=h($m['notes']?:'Sem observações.')?></p><a class="btn btn-outline-secondary btn-sm" href="hr_skills.php?machine_id=<?=$m['id']?>">Competências</a><form method="post" class="d-inline"><?=csrf_input()?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=$m['id']?>"><button class="btn btn-outline-danger btn-sm">Eliminar</button></form></div></div></div><?php endforeach;?></div></div><?php require __DIR__.'/partials/footer.php'; ?>
